//! LIVE autonomic re-fork over the REAL UDP partyline (not injected signals).
//!
//! This drives the AntColony homeostasis loop end to end against the actual
//! `swarm::broadcast` / `read_vibe` partyline (255.255.255.255:4242), exactly the
//! way live distributed-inference nodes drive it — the broadcast CLI / a node
//! emits, the controller reads the collective vibe and buds/reaps:
//!
//!   HOT  -> a background thread broadcasts a high-consciousness (5) signal;
//!           `auto::autotick` (real read_vibe) decides Bud and a scout is spawned,
//!           the audit entry is attributable to the autonomic controller, and the
//!           population stays within the DECAGON ceiling.
//!   CALM -> the hot broadcaster stops and a consciousness-0 signal is emitted;
//!           autotick decides Reap of the idle scout, never below the lone queen
//!           (the two-queen floor holds), and the audit chain still verifies.
//!
//! It uses a fake `monster-guard` (delegate/revoke exit 0; run -> sleep) and
//! `/bin/sleep` nodes so the spawns are real ledger rows over the real partyline
//! WITHOUT a fat-station or aeon-monitor — fast (seconds), no real inference.
//!
//! GATE / SKIP: in a sandboxed CI with no UDP broadcast, binding 4242 or sending
//! a broadcast (or receiving our own self-broadcast) can fail. We probe the loop
//! once up front and SKIP cleanly (eprintln + return) so plain `cargo test` stays
//! green. Mirrors the SKIP idiom in `tests/paris_subagent.rs`.

use std::os::unix::fs::PermissionsExt;
use std::path::PathBuf;
use std::sync::atomic::{AtomicBool, Ordering};
use std::sync::{Arc, Mutex};
use std::time::Duration;

use a0n_auth::ucan::issue;
use a0n_auth::{Capability, IssueOptions};

use monster_swarm::audit;
use monster_swarm::auto::{self, AutoDecision, AutoPolicy};
use monster_swarm::budget::{Caste, FleetBudget};
use monster_swarm::ops::{self, SpawnRequest, DEFAULT_GRANT_TTL_SECS};
use monster_swarm::store;
use monster_swarm::swarm::{self, SwarmSignal};

/// The shared global env ($MONSTER_GUARD_HOME etc.) is process-wide; serialize so
/// no other test observes this test's home under the runner's parallel threads.
static ENV_GUARD: Mutex<()> = Mutex::new(());

/// Fake `monster-guard`: delegate + revoke exit 0; run stays alive briefly so the
/// supervisor pid is live when the ledger is saved (same harness as the other
/// integration tests).
fn fake_guard(dir: &PathBuf) -> PathBuf {
    let bin = dir.join("monster-guard");
    let script = "#!/bin/sh\n\
         if [ \"$1\" = \"run\" ]; then\n\
         \texec sleep 30\n\
         fi\n\
         exit 0\n";
    std::fs::write(&bin, script).unwrap();
    std::fs::set_permissions(&bin, std::fs::Permissions::from_mode(0o755)).unwrap();
    bin
}

/// An isolated `$MONSTER_GUARD_HOME` with a fake guard + `/bin` node allowlist
/// (so the bud node is `sleep`). Restores + removes itself on drop.
struct Home {
    path: PathBuf,
}

impl Home {
    fn new(name: &str) -> Home {
        let path = std::env::temp_dir().join(format!("monster-swarm-{name}-{}", std::process::id()));
        let _ = std::fs::remove_dir_all(&path);
        std::fs::create_dir_all(&path).unwrap();
        std::env::set_var("MONSTER_GUARD_HOME", &path);
        let bindir = path.join("bin");
        std::fs::create_dir_all(&bindir).unwrap();
        std::env::set_var("MONSTER_GUARD_BIN", fake_guard(&bindir));
        // The bud node is /bin/sleep — a real, allowlisted, harmless process.
        std::env::set_var("MONSTER_SWARM_NODES", "/bin");
        Home { path }
    }
}

impl Drop for Home {
    fn drop(&mut self) {
        std::env::remove_var("MONSTER_GUARD_HOME");
        std::env::remove_var("MONSTER_GUARD_BIN");
        std::env::remove_var("MONSTER_SWARM_NODES");
        let _ = std::fs::remove_dir_all(&self.path);
    }
}

/// A capability granting agent/spawn + agent/reap rooted at the resident root;
/// the holder/spawner DID is the root's own DID. reap covers oath-breach too.
fn root_ucan() -> String {
    let root = store::ensure_root().expect("root");
    let caps = vec![
        Capability { can: "agent/spawn".into(), with: "agent:fleet".into(), constraints: None },
        Capability { can: "agent/reap".into(), with: "agent:fleet".into(), constraints: None },
    ];
    issue(&root, root.did(), &caps, 3600, &IssueOptions::default()).expect("ucan")
}

fn spawn_req(ucan: &str, id: &str, caste: Caste) -> SpawnRequest {
    SpawnRequest {
        ucan: ucan.to_string(),
        node: "sleep".into(),
        id: Some(id.to_string()),
        caste,
        caps: vec!["net".into()],
        // Short lease: the supervisor sleep dies promptly; we reap explicitly too.
        lease_secs: 30,
        max_secs: None,
        grant_ttl_secs: DEFAULT_GRANT_TTL_SECS,
        node_args: vec!["30".into()],
        qspec: None,
        oath: None,
        teleport: None,
    }
}

/// Probe the REAL partyline once: can we both bind+read 4242 AND receive our own
/// broadcast within a short dwell? Returns true only if the full loop works, so a
/// sandbox with no UDP broadcast SKIPs instead of failing flakily.
fn partyline_loops_back() -> bool {
    let probe = SwarmSignal {
        source_id: "autofork-live-probe".into(),
        energy: 50,
        consciousness: 5,
        pitch_class: 0,
        phase: 0,
        recalibration_event: false,
    };
    // Spin a brief reader; broadcast a few times into it; see if it lands.
    let stop = Arc::new(AtomicBool::new(false));
    let stop_tx = stop.clone();
    let sig = probe.clone();
    let tx = std::thread::spawn(move || {
        while !stop_tx.load(Ordering::Relaxed) {
            if swarm::broadcast(&sig).is_err() {
                return false;
            }
            std::thread::sleep(Duration::from_millis(20));
        }
        true
    });
    let read = swarm::read_vibe(Duration::from_millis(400));
    stop.store(true, Ordering::Relaxed);
    let sent_ok = tx.join().unwrap_or(false);
    match read {
        Ok(seen) => sent_ok && seen.contains_key("autofork-live-probe"),
        Err(_) => false,
    }
}

/// A background broadcaster holding a single signal hot on the partyline until
/// stopped. Returns the stop flag + join handle so the caller can halt it.
fn start_broadcaster(signal: SwarmSignal) -> (Arc<AtomicBool>, std::thread::JoinHandle<()>) {
    let stop = Arc::new(AtomicBool::new(false));
    let stop_tx = stop.clone();
    let handle = std::thread::spawn(move || {
        while !stop_tx.load(Ordering::Relaxed) {
            let _ = swarm::broadcast(&signal);
            std::thread::sleep(Duration::from_millis(30));
        }
    });
    (stop, handle)
}

#[test]
fn live_partyline_buds_when_hot_and_reaps_when_calm() {
    let _env = ENV_GUARD.lock().unwrap_or_else(|e| e.into_inner());
    let _home = Home::new("autofork-live");

    // ---- gate: real UDP broadcast must loop back, else SKIP cleanly ----------
    if !partyline_loops_back() {
        eprintln!(
            "SKIP: UDP broadcast partyline unavailable (cannot bind 4242 or self-broadcast \
             does not loop back in this sandbox) -> autonomic live re-fork untestable here"
        );
        return;
    }

    let ucan = root_ucan();

    // ---- seed a queen so the two-queen floor is satisfied --------------------
    // One breeder = the lone persistent queen; homeostasis buds/reaps SCOUTS
    // around it and may never reap below it.
    ops::spawn(spawn_req(&ucan, "queen", Caste::Breeder)).expect("seed queen");
    let fleet = store::load_fleet();
    assert_eq!(fleet.breeders(), 1, "the lone queen is seeded");
    assert_eq!(fleet.scouts(), 0, "no scouts yet");

    let ceiling = FleetBudget::default().population_ceiling; // DECAGON = 10
    let policy = AutoPolicy {
        node_bin: "sleep".to_string(),
        caps: vec!["net".to_string()],
        lease_secs: 30,
        ..AutoPolicy::default()
    };

    // ===== HOT: a high-consciousness signal on the wire buds a scout ==========
    let hot = SwarmSignal {
        source_id: "live-hot-node".into(),
        energy: 90,
        consciousness: 5, // >= bud_at (4) -> hot
        pitch_class: 0,
        phase: 0,
        recalibration_event: false,
    };
    let (hot_stop, hot_thread) = start_broadcaster(hot);

    // Real read_vibe over a short dwell, then decide + act (a real bud spawn).
    let hot_outcome = auto::autotick(&ucan, &policy, Duration::from_millis(500))
        .expect("autotick (hot) ran");

    // Stop the hot broadcaster now that the tick has read.
    hot_stop.store(true, Ordering::Relaxed);
    let _ = hot_thread.join();

    assert_eq!(hot_outcome.action, "bud", "a hot collective vibe buds a scout: {}", hot_outcome.reason);
    assert!(hot_outcome.nodes_talking >= 1, "the hot node was heard on the partyline");
    assert!(hot_outcome.subagent.is_some(), "the bud produced a subagent");

    let after_bud = store::load_fleet();
    assert_eq!(after_bud.scouts(), 1, "exactly one scout was budded");
    assert_eq!(after_bud.breeders(), 1, "the queen is untouched");
    assert!(
        after_bud.live() <= ceiling,
        "FRF held: {} live within the DECAGON ceiling {ceiling}",
        after_bud.live()
    );

    // The audit chain records the bud as AUTONOMIC: the most recent Spawn entry is
    // attributed to the controller (`auto:<did>`, never a bare human DID) and its
    // detail is tagged {autonomic:true, decision:"bud", reason:...}.
    let chain = audit::load();
    let last_spawn = chain
        .iter()
        .rev()
        .find(|e| e.kind == audit::EventKind::Spawn)
        .expect("a Spawn audit entry exists");
    assert!(
        last_spawn.actor.starts_with("auto"),
        "the bud's audit actor marks it autonomic, got '{}'",
        last_spawn.actor
    );
    assert_eq!(last_spawn.detail["autonomic"], true, "the bud entry is tagged autonomic");
    assert_eq!(last_spawn.detail["decision"], "bud", "the decision verb is recorded");
    assert!(
        last_spawn.detail["reason"].as_str().unwrap_or("").contains("budding"),
        "the decide() reason is in the audit detail: {}",
        last_spawn.detail["reason"]
    );
    // The queen's spawn (the human-seeded one) is NOT autonomic — attribution is
    // scoped, not global.
    let queen_spawn = chain
        .iter()
        .find(|e| e.kind == audit::EventKind::Spawn && e.subject == "queen")
        .expect("the queen's spawn entry exists");
    assert!(
        !queen_spawn.actor.starts_with("auto"),
        "the human-seeded queen spawn is NOT tagged autonomic, got '{}'",
        queen_spawn.actor
    );

    // The post-bud chain still verifies (contiguous, signed, no double-count).
    let report = audit::verify();
    assert!(report.ok, "the audit chain verifies after the autonomic bud: {}", report.reason);

    // ===== CALM: a consciousness-0 signal reaps the idle scout ================
    // Hold a calm signal on the wire so the collective vibe reads <= reap_below.
    let calm = SwarmSignal {
        source_id: "live-calm-node".into(),
        energy: 5,
        consciousness: 0, // <= reap_below (0) -> calm
        pitch_class: 0,
        phase: 0,
        recalibration_event: false,
    };
    let (calm_stop, calm_thread) = start_broadcaster(calm);

    let calm_outcome = auto::autotick(&ucan, &policy, Duration::from_millis(500))
        .expect("autotick (calm) ran");

    calm_stop.store(true, Ordering::Relaxed);
    let _ = calm_thread.join();

    assert_eq!(
        calm_outcome.action, "reap",
        "a calm collective vibe vents the idle scout: {}",
        calm_outcome.reason
    );

    let after_reap = store::load_fleet();
    assert_eq!(after_reap.scouts(), 0, "the idle scout was reaped");
    assert_eq!(
        after_reap.breeders(),
        1,
        "the two-queen floor holds: the lone queen is NEVER reaped below"
    );
    assert!(after_reap.live() >= 1, "the colony never collapses to nothing");

    // The reap is recorded as autonomic too (same scoped attribution).
    let chain2 = audit::load();
    let last_reap = chain2
        .iter()
        .rev()
        .find(|e| e.kind == audit::EventKind::Reap)
        .expect("a Reap audit entry exists");
    assert!(
        last_reap.actor.starts_with("auto"),
        "the reap's audit actor marks it autonomic, got '{}'",
        last_reap.actor
    );
    assert_eq!(last_reap.detail["autonomic"], true, "the reap entry is tagged autonomic");
    assert_eq!(last_reap.detail["decision"], "reap", "the decision verb is recorded");

    // Final integrity: the whole self-regulation history verifies.
    let final_report = audit::verify();
    assert!(
        final_report.ok,
        "the audit chain verifies after the full hot->bud, calm->reap cycle: {}",
        final_report.reason
    );

    // ---- cleanup: reap any remaining spawned nodes (the queen) --------------
    // The scout is already reaped; revoke the queen so no sleep supervisor leaks
    // (an oath-breach overrides the two-queen floor, so it can be torn down).
    let _ = ops::oath_breach(ops::BreachRequest {
        ucan: ucan.clone(),
        id: "queen".into(),
        reason: "test teardown".into(),
        sig_hex: None,
    });
    // The temp home (and its fake guard + ledger) is removed by Home::drop.

    eprintln!(
        "[autofork-live] OK: hot->bud (scout spawned, autonomic), calm->reap (floor held), \
         FRF within DECAGON, audit verified across {} entries",
        final_report.entries
    );
}

/// A pure decide() sanity check that runs even when the partyline is unavailable,
/// so this test file always contributes one always-on assertion: a hot vibe over
/// a one-queen fleet (with room under the ceiling) is a Bud.
#[test]
fn hot_vibe_decides_bud_pure() {
    let _env = ENV_GUARD.lock().unwrap_or_else(|e| e.into_inner());
    // decide() is pure / no I/O, but it loads no home; still, keep the env serial
    // for consistency with the live test sharing the global env.
    let policy = AutoPolicy::default();
    let mut fleet = monster_swarm::ledger::Fleet::default();
    fleet.add(monster_swarm::ledger::new_subagent(
        "q".into(), "agent-q".into(), "did:key:zA".into(), "did:key:zT".into(),
        Caste::Breeder, vec![], "sleep".into(), vec![], 30, None, None, false, None, 1,
    ));
    let hot = SwarmSignal {
        source_id: "collective".into(),
        energy: 90,
        consciousness: 5,
        pitch_class: 0,
        phase: 0,
        recalibration_event: false,
    };
    assert!(
        matches!(
            auto::decide(&policy, &hot, &fleet, &FleetBudget::default()),
            AutoDecision::Bud { .. }
        ),
        "a hot vibe over a one-queen fleet with ceiling room decides Bud"
    );
}
